async def _install_prereqs(
    package_manager: PackageManager,
    *,
    deadline: Deadline,
    yes: bool,
) -> None:
    # fail fast if no escalation path is available for package installs
    if os.geteuid() != 0 and not can_escalate():
        msg = (
            "Bertrand requires root escalation to install host bootstrap dependencies, "
            "but neither 'sudo' nor 'doas' is available.  Install one of these tools "
            "or manually rerun `bertrand init` as root."
        )
        raise PermissionError(msg)

    # package mapping for bootstrap-required host tools across package managers
    packages = PREREQS.get(package_manager.name)
    if packages is None:
        msg = (
            "Unsupported package manager for prerequisite installation: "
            f"'{package_manager.name}' (supported: {sorted(PREREQS)})"
        )
        raise OSError(msg)

    # detect missing required bootstrap tools
    missing: set[str] = set()
    for tool, package in packages.items():
        if package in missing:
            continue
        if shutil.which(tool):
            continue
        missing.add(package)
    if not missing:
        return  # idempotently skip if all tools are already available

    # install missing tools
    if not confirm(
        "Bertrand requires host bootstrap tools to configure runtime "
        f"dependencies and shared state (missing: {', '.join(missing)}).  Would "
        "you like Bertrand to install missing packages now (requires sudo)?\n[y/N] ",
        yes=yes,
    ):
        msg = "Installation declined by user."
        raise PermissionError(msg)
    await package_manager.install(
        packages=sorted(missing),
        yes=yes,
        deadline=deadline,
    )

    # verify all required tools after installation
    unresolved: list[str] = [
        name for name, cmd in CHECK_PREREQS if not any(shutil.which(c) for c in cmd)
    ]
    if unresolved:
        msg = (
            "Prerequisite installation completed, but required host bootstrap tools "
            f"are still missing: {', '.join(unresolved)}."
        )
        raise OSError(msg)


@dataclass(frozen=True)
class User:
    """A simple structure representing a user identity by user ID and group ID.

    Attributes
    ----------
    uid : int
        The numeric user ID.
    gid : int
        The numeric group ID.
    name : str
        The username.
    home : Path
        The path to the user's home directory.
    """

    uid: int = field(init=False)
    gid: int = field(init=False)
    name: str = field(init=False)
    home: Path = field(init=False)

    def __post_init__(self) -> None:
        """Resolve the effective host user identity."""
        euid = os.geteuid()
        sudo_uid = os.environ.get("SUDO_UID")
        sudo_user = os.environ.get("SUDO_USER")
        if euid == 0 and sudo_uid:
            object.__setattr__(self, 'uid', int(sudo_uid))
            pw = pwd.getpwuid(self.uid)
            object.__setattr__(self, 'gid', pw.pw_gid)
            object.__setattr__(self, 'name', sudo_user or pw.pw_name)
            object.__setattr__(self, 'home', Path(pw.pw_dir))
        else:
            object.__setattr__(self, 'uid', os.getuid())
            pw = pwd.getpwuid(self.uid)
            object.__setattr__(self, 'gid', pw.pw_gid)
            object.__setattr__(self, 'name', pw.pw_name)
            object.__setattr__(self, 'home', Path(pw.pw_dir))


@dataclass(frozen=True)
class UserGroup:
    """A simple struct representing a user's membership status in a host group.

    Attributes
    ----------
    user : str
        The username to which this status applies.
    group : str
        The group name to which this status applies.
    configured : bool
        Whether the user is configured as a member of the group (either as a primary or
        secondary member).
    active : bool
        Whether the user's current session is active in the group (i.e. whether the
        group is included in the user's current group list, which is determined at
        login and may need to be refreshed via `newgrp` or a logout/login cycle).
    """

    user: str
    name: str
    gid: int = field(init=False)
    configured: bool = field(init=False)
    active: bool = field(init=False)

    def __post_init__(self) -> None:
        """Get the corresponding gid, configured, and active status for the group."""
        try:
            group_info = grp.getgrnam(self.name)
        except KeyError:
            object.__setattr__(self, 'gid', -1)
            object.__setattr__(self, 'configured', False)
            object.__setattr__(self, 'active', False)
            return

        object.__setattr__(self, 'gid', group_info.gr_gid)
        try:
            primary_gid = pwd.getpwnam(self.user).pw_gid
        except KeyError:
            primary_gid = None
        object.__setattr__(
            self,
            'configured',
            self.user in group_info.gr_mem or primary_gid == self.gid,
        )
        object.__setattr__(
            self, 'active', self.gid in os.getgroups() or os.getegid() == self.gid
        )

    async def activate(self, *, yes: bool, deadline: Deadline) -> None:
        """Ensure host group membership.

        Parameters
        ----------
        yes : bool
            If True, automatically confirm any prompts for fixing group membership.
        deadline : Deadline
            Maximum time in seconds to wait for required host commands.

        Raises
        ------
        PermissionError
            If the user declines to update their group membership, or if the update
            requires root privileges and they are not available.
        OSError
            If group membership still isn't properly configured after attempting to
            update it.
        """
        group = self
        if group.configured and group.active:
            return

        # ensure membership
        if not group.configured:
            if not confirm(
                f"Bertrand must add user {group.user!r} to the {group.name!r} "
                f"group in order to avoid future root escalation.  Would you like "
                "Bertrand to add this membership now (requires sudo)?\n[y/N] ",
                yes=yes,
            ):
                msg = f"{group.name} group membership update declined by user."
                raise PermissionError(msg)
            if os.geteuid() != 0 and not can_escalate():
                msg = (
                    f"Updating {group.name} group membership requires root "
                    "privileges; "
                    "sudo not available."
                )
                raise PermissionError(msg)
            await run(
                sudo(
                    ["usermod", "-a", "-G", group.name, group.user],
                    non_interactive=yes,
                ),
                deadline=deadline,
            )
            group = UserGroup(user=group.user, name=group.name)
            if not group.configured:
                msg = f"failed to add user '{group.user}' to group '{group.name}'"
                raise OSError(msg)

        # warn if group membership is not active in current session
        if not group.active:
            warn(
                f"added {group.user!r} to the {group.name!r} group, but "
                f"sudo is still required for this session.  Run `newgrp {group.name}` "
                "or log out and back in to pick up the new group privileges before "
                "proceeding."
            )


async def _create_bertrand_group(*, deadline: Deadline, yes: bool) -> grp.struct_group:
    # idempotently skip if group is already present
    try:
        return grp.getgrnam(BERTRAND_GROUP)
    except KeyError:
        pass

    if not confirm(
        f"Bertrand uses a shared host group named '{BERTRAND_GROUP}' for "
        "unprivileged access to global runtime state.  Create this system group now "
        "(requires sudo)?\n"
        "[y/N] ",
        yes=yes,
    ):
        msg = "Bertrand shared-group bootstrap declined by user."
        raise PermissionError(msg)
    if os.geteuid() != 0 and not can_escalate():
        msg = (
            f"Creating group '{BERTRAND_GROUP}' requires root privileges; sudo not "
            "available."
        )
        raise PermissionError(msg)
    try:
        await run(
            sudo(
                ["groupadd", "--system", BERTRAND_GROUP],
                non_interactive=yes,
            ),
            capture_output=True,
            deadline=deadline,
        )
    except CommandError:
        with contextlib.suppress(KeyError):
            return grp.getgrnam(BERTRAND_GROUP)
        raise

    try:
        return grp.getgrnam(BERTRAND_GROUP)
    except KeyError as err:
        msg = f"Failed to create shared Bertrand group '{BERTRAND_GROUP}'."
        raise OSError(msg) from err


def require_bertrand_group() -> None:
    """Raise an error if the user is not an active member of the Bertrand user group.

    Raises
    ------
    OSError
        If the user is not configured as a member of the Bertrand group, or if they are
        configured but their membership is not active in the current session.
    """
    global _BERTRAND_GROUP_READY
    if _BERTRAND_GROUP_READY:
        return

    user = User()
    group = UserGroup(user=user.name, name=BERTRAND_GROUP)
    if not group.configured:
        msg = (
            f"user {group.user!r} is not in the '{BERTRAND_GROUP}' group.  Rerun "
            "`bertrand init` to establish permissions for this user."
        )
        raise OSError(msg)
    if not group.active:
        msg = (
            f"user {group.user!r} is in the '{BERTRAND_GROUP}' group, but membership "
            "has not yet been activated for the current session.  Log out and back "
            f"into the session or run `newgrp {BERTRAND_GROUP}` to continue."
        )
        raise OSError(msg)
    _BERTRAND_GROUP_READY = True


def abspath(path: Path) -> Path:
    """Normalize a filesystem path without resolving symlinks.

    Parameters
    ----------
    path : Path
        The path to normalize.

    Returns
    -------
    Path
        The normalized path.
    """
    return Path(os.path.abspath(path.expanduser()))  # noqa: PTH100


def symlink_points_to(path: Path, target: Path) -> bool:
    """Return whether `path` is a symlink to `target`.

    Parameters
    ----------
    path : Path
        Candidate alias path.
    target : Path
        Expected hidden mount destination.

    Returns
    -------
    bool
        True when `path` is a symlink whose raw target is absolute and exactly
        equal to `target`.
    """
    try:
        if path.is_symlink():
            current = path.readlink()
            return current.is_absolute() and current == target
    except OSError:
        pass
    return False


def atomic_symlink(source: Path, target: Path, *, private: bool = False) -> None:
    """Atomically create a symbolic link, avoiding race conditions and partial writes.

    Parameters
    ----------
    source : Path
        The source path the symbolic link should point to.
    target : Path
        The target path of the symbolic link to create.
    private : bool, optional
        Whether to set private permissions (0600) on the created symlink, by default
        False.
    """
    target.parent.mkdir(parents=True, exist_ok=True)
    tmp = target.with_name(f"{target.name}.tmp.{uuid.uuid4().hex}")
    tmp.symlink_to(source)
    if private:
        tmp.chmod(0o600)
    tmp.replace(target)


def atomic_write_text(
    path: Path,
    text: str,
    encoding: str | None = None,
    *,
    mode: int = 0o666,
    gid: int | None = None,
) -> None:
    """Atomically write text to a file, avoiding race conditions and partial writes.

    Parameters
    ----------
    path : Path
        The path to write to.
    text : str
        The text to write.
    encoding : str | None, optional
        The text encoding to use (default is None, which uses the system default).
    mode : int, optional
        The file mode to set on the written file, by default 0o666, which grants
        read-write permissions to all users.
    gid : int | None, optional
        The group ID to set on the written file, by default None.
    """
    path.parent.mkdir(parents=True, exist_ok=True)
    tmp = path.with_name(f"{path.name}.tmp.{uuid.uuid4().hex}")
    tmp.write_text(text, encoding=encoding)
    with tmp.open("r+", encoding=encoding) as f:
        f.flush()
        os.fsync(f.fileno())
    if gid is not None:
        os.chown(tmp, -1, gid)
    tmp.chmod(mode)
    tmp.replace(path)


async def _require_systemd(deadline: Deadline) -> None:
    if platform.system() != "Linux":
        msg = (
            "Bertrand state bootstrap requires a Linux host with systemd available "
            "as the active init/service manager."
        )
        raise OSError(msg)
    systemctl = shutil.which("systemctl")
    if systemctl is None:
        msg = (
            "Bertrand requires systemd (`systemctl`) to manage the runtime tmpfs "
            "mount and owned k0s service.  Installing a systemd package is not enough "
            "unless the host is booted with systemd as its active service manager."
        )
        raise OSError(msg)
    try:
        await run(
            [
                systemctl,
                "--system",
                "show",
                "--property=Version",
                "--value",
            ],
            capture_output=True,
            deadline=deadline,
        )
    except (CommandError, TimeoutExpired) as err:
        msg = (
            "Bertrand requires an active systemd system manager to manage the runtime "
            "tmpfs mount and owned k0s service.  This host has `systemctl`, but the "
            "system manager did not respond.  Run Bertrand on a systemd-booted Linux "
            "host; for WSL, enable systemd and restart the distribution; containers, "
            "chroots, and non-systemd init systems are not supported by this bootstrap "
            "path."
        )
        raise OSError(msg) from err


class HostLock:
    """A re-entrant, OS-level, asynchronous file lock."""

    path: Path
    _key: str
    _fd: int | None
    _owner: asyncio.Task[Any] | None
    _depth: int

    def __new__(cls, path: Path) -> Self:
        """Construct or return a shared lock instance for the given path.

        Parameters
        ----------
        path : Path
            Local file path used for host-level locking.

        Returns
        -------
        Self
            Shared lock instance for the resolved lock path.

        Raises
        ------
        OSError
            If the lock path is invalid.
        """
        path = path.expanduser().resolve()
        if path.exists() and path.is_dir():
            msg = (
                f"host lock path must be a file, but a directory already exists: {path}"
            )
            raise OSError(msg)

        # allow re-entrancy with unique lock instances per owning task
        with LOCK_GUARD:
            key = str(path)
            self = HOST_LOCKS.get(key)
            if self is None:
                self = super().__new__(cls)
                self.path = path
                self._key = key
                self._fd = None
                self._owner = None
                self._depth = 0
                HOST_LOCKS[key] = self
        return cast("Self", self)

    @staticmethod
    def _get_owner() -> asyncio.Task[Any]:
        try:
            task = asyncio.current_task()
        except RuntimeError:
            task = None
        if task is None:
            msg = "HostLock requires an active asyncio Task"
            raise RuntimeError(msg)
        return task

    def _clear_owner(
        self,
        *,
        owner: asyncio.Task[Any] | None = None,
        unregister: bool = False,
    ) -> None:
        with LOCK_GUARD:
            if owner is not None and self._owner != owner:
                return
            self._owner = None
            self._depth = 0
            if unregister:
                HOST_LOCKS.pop(self._key, None)

    @staticmethod
    def _permissions_ready(stat_info: os.stat_result, group_gid: int) -> bool:
        return (
            stat_info.st_gid == group_gid
            and (stat_info.st_mode & 0o777) == LOCK_FILE_MODE
        )

    def _set_permissions(self, fd: int, group_gid: int) -> None:
        errors: list[OSError] = []
        if hasattr(os, "fchown"):
            try:
                os.fchown(fd, -1, group_gid)
            except OSError as err:
                errors.append(err)
        if hasattr(os, "fchmod"):
            try:
                os.fchmod(fd, LOCK_FILE_MODE)
            except OSError as err:
                errors.append(err)

        stat_info = os.fstat(fd)
        if self._permissions_ready(stat_info, group_gid):
            return

        detail = "; ".join(str(err) for err in errors)
        msg = (
            f"failed to secure host lock {self.path} for group '{BERTRAND_GROUP}' "
            f"with mode {LOCK_FILE_MODE:o}"
        )
        if detail:
            msg = f"{msg}: {detail}"
        raise OSError(msg)

    def _create_lock_file(self) -> int:
        group = grp.getgrnam(BERTRAND_GROUP)

        try:
            fd = os.open(self.path, os.O_RDWR | os.O_CREAT, LOCK_FILE_MODE)
        except OSError as err:
            if err.errno not in {errno.EACCES, errno.EPERM}:
                raise
            try:
                stat_info = self.path.stat()
            except OSError as stat_err:
                msg = f"cannot open or inspect host lock {self.path}"
                raise OSError(msg) from stat_err
            if self._permissions_ready(stat_info, group.gr_gid):
                msg = (
                    f"cannot open host lock {self.path} even though it is already "
                    f"group-owned by '{BERTRAND_GROUP}' with mode "
                    f"{LOCK_FILE_MODE:o}"
                )
                raise OSError(msg) from err
            msg = (
                f"cannot open host lock {self.path}: existing lock file is not "
                f"group-owned by '{BERTRAND_GROUP}' with mode "
                f"{LOCK_FILE_MODE:o}.  Remove the stale lock file or fix its ownership "
                "and permissions, then retry."
            )
            raise OSError(msg) from err

        try:
            if os.name != "nt":
                self._set_permissions(fd, group.gr_gid)
        except OSError:
            os.close(fd)
            raise
        return fd

    async def _try_acquire_file(self) -> bool:
        self.path.parent.mkdir(parents=True, exist_ok=True)
        if self._fd is None:
            self._fd = self._create_lock_file()

        # Windows file lock on a 1-byte region
        if os.name == "nt":
            os.lseek(self._fd, 0, os.SEEK_SET)
            if os.fstat(self._fd).st_size < 1:
                os.write(self._fd, b"\0")
            try:
                msvcrt.locking(self._fd, msvcrt.LK_NBLCK, 1)
            except OSError as err:
                if err.errno in (errno.EACCES, errno.EDEADLK) or getattr(
                    err, "winerror", None
                ) in {33, 36}:
                    return False
                raise
            return True

        # POSIX non-blocking file lock
        try:
            fcntl.flock(self._fd, fcntl.LOCK_EX | fcntl.LOCK_NB)
        except BlockingIOError:
            return False
        except OSError as err:
            if err.errno in (errno.EACCES, errno.EAGAIN):
                return False
            raise
        return True

    async def _acquire_file(self, deadline: Deadline) -> bool:
        while not await self._try_acquire_file():
            remaining = deadline.remaining
            if remaining <= 0:
                return False
            await deadline.sleep(SHORT_DELAY)
        return True

    async def _release_file(self) -> None:
        if self._fd is None:
            return
        fd = self._fd
        self._fd = None
        try:
            if os.name == "nt":
                os.lseek(fd, 0, os.SEEK_SET)
                with contextlib.suppress(OSError):
                    msvcrt.locking(fd, msvcrt.LK_UNLCK, 1)
            else:
                with contextlib.suppress(OSError):
                    fcntl.flock(fd, fcntl.LOCK_UN)
        finally:
            os.close(fd)
            with contextlib.suppress(OSError):
                self.path.unlink()

    async def lock(self, deadline: Deadline) -> Self:
        """Acquire this file lock, waiting for this lock's timeout if needed.

        Parameters
        ----------
        deadline : Deadline
            The deadline by which the lock must be acquired before raising a
            `TimeoutError`.

        Returns
        -------
        Self
            This lock instance after acquisition.

        Raises
        ------
        TimeoutError
            If the lock cannot be acquired before its timeout.
        OSError
            If the lock file cannot be created, locked, or cleaned up after a failed
            acquisition.
        """
        owner = self._get_owner()

        # fast-path: same task re-entrancy
        while True:
            with LOCK_GUARD:
                if self._owner is None:
                    self._owner = owner
                    self._depth = 1
                    break
                if self._owner == owner:
                    self._depth += 1
                    return self
            if deadline.remaining <= 0:
                msg = (
                    f"could not acquire lock at {self.path} within {deadline.timeout} "
                    "seconds"
                )
                raise TimeoutError(msg)
            await deadline.sleep(SHORT_DELAY)

        # slow path: acquire via backend
        try:
            if not await self._acquire_file(deadline):
                msg = f"could not acquire lock within {deadline.timeout} seconds"
                raise TimeoutError(msg)
        except OSError:
            with contextlib.suppress(OSError):
                await self._release_file()
            self._clear_owner(owner=owner)
            raise

        return self

    async def try_lock(self) -> bool:
        """Attempt to acquire this lock immediately, without waiting on contention.

        Returns
        -------
        bool
            `True` if the lock was successfully acquired, or `False` if the lock is
            currently held by another task or process.

        Raises
        ------
        OSError
            If the lock file cannot be created, locked, or cleaned up after a failed
            acquisition.
        """
        owner = self._get_owner()

        # fast-paths: re-entrant success or immediate contention failure
        with LOCK_GUARD:
            if self._owner == owner:
                self._depth += 1
                return True
            if self._owner is not None:
                return False
            self._owner = owner
            self._depth = 1

        # slow path: single backend attempt only
        try:
            acquired = await self._try_acquire_file()
        except OSError:
            with contextlib.suppress(OSError):
                await self._release_file()
            self._clear_owner(owner=owner)
            raise

        if acquired:
            return True

        self._clear_owner(owner=owner)
        return False

    async def unlock(self, *, ignore_errors: bool = False) -> None:
        """Release this lock once.  Re-entrant lock depth is decremented.

        Parameters
        ----------
        ignore_errors : bool
            If `True`, suppress any exceptions raised by the backend release operation,
            which may be desirable if the lock is being released in response to an
            error condition and the caller wishes to preserve the original exception.
            Defaults to `False`, in which case backend errors will be raised after
            releasing the lock and clearing lock state.

        Raises
        ------
        RuntimeError
            If the current task does not hold this lock.
        OSError
            If the lock file cannot be released and `ignore_errors` is `False`.
        """
        owner = self._get_owner()
        with LOCK_GUARD:
            if self._owner != owner or self._depth < 1:
                msg = "lock is not held by the current owner"
                raise RuntimeError(msg)
            self._depth -= 1
            if self._depth > 0:
                return  # re-entrant case

        try:
            await self._release_file()
        except OSError:
            if not ignore_errors:
                raise
        finally:
            self._clear_owner(unregister=True)

    def __bool__(self) -> bool:
        """Return whether this lock is currently held by any task or process.

        Returns
        -------
        bool
            `True` if this lock is currently held by any task or process, or `False
            if this lock is currently free.
        """
        with LOCK_GUARD:
            return self._depth > 0

    def __repr__(self) -> str:
        """Return a string representation of this lock.

        Returns
        -------
        str
            A string representation of this lock.
        """
        return f"{type(self).__name__}(path={self.path!r})"


@dataclass(frozen=True)
class HostMount:
    r"""Describe one host mount table entry.

    Attributes
    ----------
    mount_point : Path
        Mountpoint path from mountinfo field 5 (pre-`-` section). Kernel escaping
        is decoded before storage (`\\040`, `\\011`, `\\012`, `\\134`).
    fs_type : str
        Filesystem type from the first field after the `-` separator.
    source : str
        Kernel-reported mount source from the second field after `-`.
    """

    mount_point: Path
    fs_type: str = field(default="")
    source: str = field(default="")

    @classmethod
    def local(cls) -> tuple[Self, ...]:
        """Parse and return local mount entries from `/proc/self/mountinfo`.

        Returns
        -------
        tuple[HostMount, ...]
            Parsed entries with decoded mountpoint paths, sorted by mount point.

        Raises
        ------
        OSError
            If the host mount table cannot be read.
        """
        try:
            lines = HOST_MOUNTS.read_text(encoding="utf-8").splitlines()
        except OSError as err:
            msg = f"failed to inspect host mount table: {err}"
            raise OSError(msg) from err

        out: dict[Path, Self] = {}
        for line in lines:
            parts = line.strip().split()
            try:
                if len(parts) < 10:
                    continue
                sep = parts.index("-")
                if sep + 2 >= len(parts):
                    continue
            except ValueError:
                continue

            info = cls(
                mount_point=abspath(
                    Path(
                        parts[4]
                        .replace("\\040", " ")
                        .replace("\\011", "\t")
                        .replace("\\012", "\n")
                        .replace("\\134", "\\")
                    )
                ),
                fs_type=parts[sep + 1],
                source=parts[sep + 2],
            )
            out[info.mount_point] = info
        return tuple(
            sorted(out.values(), key=lambda entry: entry.mount_point.as_posix())
        )

    @classmethod
    def under(cls, root: Path) -> tuple[Self, ...]:
        """Return mounted paths at or below `root`.

        Parameters
        ----------
        root : Path
            Root path to check for mounted entries at or below.

        Returns
        -------
        tuple[HostMount, ...]
            Parsed mount entries mounted at or below `root`, sorted by mount point.
        """
        prefix = abspath(root)
        return tuple(
            entry for entry in cls.local() if entry.mount_point.is_relative_to(prefix)
        )

    @classmethod
    def search(cls, path: Path) -> Self | None:
        """Return the exact mounted entry for `path`, if present.

        Parameters
        ----------
        path : Path
            Path to check for an exact mountpoint match.

        Returns
        -------
        HostMount | None
            Matching mount entry, or None when `path` is not mounted.
        """
        target = abspath(path)
        return next(
            (entry for entry in cls.local() if entry.mount_point == target),
            None,
        )

    async def unmount(self, *, deadline: Deadline, force: bool) -> bool:
        """Detach this mounted entry from the host.

        Parameters
        ----------
        deadline : Deadline
            Maximum command budget for this unmount operation.
        force : bool
            If True, pass `-f` to `umount`.

        Returns
        -------
        bool
            True if this mount was detached, False if it was already detached.

        Raises
        ------
        OSError
            If unmounting fails or the mount remains attached.
        """
        if os.name != "posix" or platform.system() != "Linux":
            msg = "host mounts are only supported on Linux platforms"
            raise OSError(msg)
        cmd = ["umount"]
        if force:
            cmd.append("-f")
        cmd.append(str(self.mount_point))
        try:
            await run(
                sudo(cmd),
                capture_output=True,
                deadline=deadline,
            )
        except CommandError as err:
            if HostMount.search(self.mount_point) is None:
                return False
            msg = f"unmount command failed:\n{err}"
            raise OSError(msg) from err

        if HostMount.search(self.mount_point) is not None:
            msg = f"failed to unmount volume at {self.mount_point}"
            raise OSError(msg)
        return True


@dataclass(frozen=True)
class State:
    """Bertrand-managed host state layout and filesystem primitives.

    Attributes
    ----------
    unit : Path
        Absolute systemd unit path for the runtime tmpfs service.
    root : Path
        The absolute root directory of Bertrand's persistent state.
    lock : HostLock
        Absolute path to a global lock file that guards the global cluster bootstrap
        portion of the `bertrand init` command.  This is stored outside the state
        directory itself in order to allow the lock to cover the entire bootstrap
        process.
    id_file : Path
        Absolute path to a durable file containing a UUID for this host.  This file will
        be generated by `bertrand init` when the initial state directory is created.
    bin : Path
        Absolute path to a directory containing executable files for Bertrand's internal
        control plane.
    cache : Path
        Absolute path to a cache directory for storing persistent cache files for
        internal tooling used by Bertrand's control plane.
    runtime : Path
        Absolute path to a tmpfs-backed runtime directory used to store transient files
        that should not persist across reboots, such as locks, secret files, join
        tokens, etc.  Note that this does not encrypt the contents in any way, so the
        contents must be treated as world-readable as long as it exists on disk.
        Volatility is simply one component of Bertrand's security model.
    mount_locks : Path
        Absolute path to a subdirectory used to store host-local, per-repository lock
        files for the project bootstrap portion of the `bertrand init` command.  Using
        tiered global > repo locks reduces contention while still properly synchronizing
        concurrent `init` commands, by transitioning at the boundary between the global
        and per-repository bootstrap phases.
    mount : Path
        Absolute path to a repository catalog holding metadata for all the Bertrand
        repositories that are currently mounted to this host.
    dir_mode : int
        The file mode to set on created directories within the state root, by default
        0o2770, which grants read-write-execute permissions to the owner and group and
        causes subdirectories to inherit the group ID of the parent directory.
    file_mode : int
        The file mode to set on created files within the state root, by default 0o640,
        which grants read-write permissions to the cluster's owner and read permissions
        to the group.
    bin_mode : int
        The file mode to set on executable files within the state root, by default
        0o750, which grants read-write-execute permissions to the owner and read-execute
        permissions to the group.
    kube : State.Kube
        A nested namespace that encapsulates Kubernetes-related paths within the wider
        state directory structure.
    """

    unit: Path = field(
        default=(
            ROOT_DIR / "etc" / "systemd" / "system" / "var-lib-bertrand-runtime.mount"
        )
    )
    root: Path = field(default=ROOT_DIR / "var" / "lib" / "bertrand")
    lock: HostLock = field(
        default_factory=lambda: HostLock(ROOT_DIR / "tmp" / "bertrand-state.lock")
    )
    id_file: Path = field(default=Path("host_id"))
    bin: Path = field(default=Path("bin"))
    cache: Path = field(default=Path("cache"))
    runtime: Path = field(default=Path("runtime"))
    mount: Path = field(default=Path("mount"))
    mount_locks: Path = field(default=Path("runtime") / "init")
    dir_mode: int = field(default=0o2770)
    file_mode: int = field(default=0o640)
    bin_mode: int = field(default=0o750)

    @dataclass
    class Kube:
        """Namespace for Kubernetes-related paths within the main State structure.

        Attributes
        ----------
        bootstrap : Path
            A k0s configuration file used to initialize and run an isolated kubernetes
            cluster on this host equipped with Bertrand's internal control plane.
        config : Path
            Absolute path to a private kubeconfig file which Bertrand uses to access and
            customize the kubernetes client API.
        bin : Path
            Absolute path to the kubernetes client executable.
        cache : Path
            Absolute path to the kubernetes data directory for the integrated Kubernetes
            cluster.
        runtime : Path
            Absolute path to a runtime directory for the integrated Kubernetes cluster,
            used to store transient files such as locks, secret files, join tokens, etc.
        lock : Path
            Absolute path to a lock file used to coordinate access to the Kubernetes
            cluster across multiple concurrent Bertrand processes.
        token : Path
            Absolute path to a file containing a join token for the Kubernetes cluster,
            if available.
        """

        bootstrap: Path = field(default=Path("kube") / "bootstrap.yaml")
        config: Path = field(default=Path("kube") / "config")
        bin: Path = field(default=Path("bin") / "k0s")
        cache: Path = field(default=Path("cache") / "kube" / "data")
        runtime: Path = field(default=Path("runtime") / "k0s")
        lock: Path = field(default=Path("runtime") / "kube" / ".lock")
        token: Path = field(default=Path("kube") / "join-token")

    kube: Kube = field(default_factory=Kube)

    @property
    def id(self) -> str:
        """Return this host's durable Bertrand UUID hex string.

        Returns
        -------
        str
            The current host ID as normalized UUID hex.

        Raises
        ------
        OSError
            If the host ID file is missing or invalid.
        """
        path = self.id_file
        try:
            return uuid.UUID(path.read_text(encoding="utf-8").strip()).hex
        except (OSError, ValueError) as err:
            msg = f"failed to read Bertrand host identity at {path}"
            raise OSError(msg) from err

    def __post_init__(self) -> None:
        """Validate the state layout.

        Raises
        ------
        ValueError
            If any of the relative paths escape the root directory or are absolute.
        """
        if not self.unit.is_absolute():
            msg = f"unit path must be absolute: {self.unit}"
            raise ValueError(msg)
        if not self.root.is_absolute():
            msg = f"root path must be absolute: {self.root}"
            raise ValueError(msg)
        object.__setattr__(self, "unit", self.unit.expanduser().resolve(strict=False))
        object.__setattr__(self, "root", self.root.expanduser().resolve(strict=False))
        for attr in ("id_file", "bin", "cache", "runtime", "mount", "mount_locks"):
            object.__setattr__(self, attr, self.path(getattr(self, attr)))
        for attr in ("bootstrap", "config", "bin", "cache", "runtime", "lock", "token"):
            object.__setattr__(self.kube, attr, self.path(getattr(self.kube, attr)))

    def path(self, path: Path) -> Path:
        """Return an absolute path below the managed state root.

        Parameters
        ----------
        path : Path
            A managed state path to resolve.  If the path is relative, then it will
            be interpreted as relative to the state root.  If the path is absolute,
            then it will be used as-is.  In both cases, the normalized path must be
            contained within the state root.

        Returns
        -------
        Path
            Absolute path beneath `root`.

        Raises
        ------
        ValueError
            If the path is not absolute or escapes the managed state root.
        """
        if not path.is_absolute():
            path = self.root / path
        path = path.resolve(strict=False)
        if not path.is_relative_to(self.root):
            msg = f"state path is not contained under {self.root}: {path}"
            raise ValueError(msg)
        return path

    @staticmethod
    async def _host_install(
        target: Path,
        source: Path,
        *,
        group: str,
        mode: int,
        deadline: Deadline,
    ) -> None:
        await run(
            sudo(
                [
                    "install",
                    "-D",
                    "-m",
                    f"{mode:o}",
                    "-o",
                    "root",
                    "-g",
                    group,
                    str(source),
                    str(target),
                ],
                non_interactive=True,
            ),
            deadline=deadline,
        )

    async def mkdir(self, path: Path, *, deadline: Deadline) -> None:
        """Create a managed root-owned state directory with the configured permissions.

        Parameters
        ----------
        path : Path
            Absolute path to the directory to create.  This path must be a descendant
            of the `root` directory.
        deadline : Deadline
            Maximum time in seconds to wait for required host commands.
        """
        await run(
            sudo(
                [
                    "install",
                    "-d",
                    "-m",
                    f"{self.dir_mode:o}",
                    "-o",
                    "root",
                    "-g",
                    BERTRAND_GROUP,
                    str(self.path(path)),
                ],
                non_interactive=True,
            ),
            deadline=deadline,
        )

    async def write(self, path: Path, text: str, *, deadline: Deadline) -> None:
        """Write one managed root-owned state file.

        Parameters
        ----------
        path : Path
            Relative path to the file to write beneath the state root.
        text : str
            The text content to write to the file, which will be UTF-8 encoded.
        deadline : Deadline
            Maximum time in seconds to wait for required host commands.
        """
        fd: int | None = None
        temp_file: Path | None = None
        try:
            fd, name = tempfile.mkstemp(prefix="bertrand-state.", suffix=".tmp")
            temp_file = Path(name)
            os.write(fd, text.encode("utf-8"))
            os.fsync(fd)
            os.close(fd)
            fd = None
            await self._host_install(
                self.path(path),
                temp_file,
                mode=self.file_mode,
                group=BERTRAND_GROUP,
                deadline=deadline,
            )
        finally:
            if fd is not None:
                with contextlib.suppress(OSError):
                    os.close(fd)
            if temp_file is not None:
                temp_file.unlink(missing_ok=True)

    async def install(self, source: Path, path: Path, *, deadline: Deadline) -> None:
        """Install one managed root-owned executable file.

        Parameters
        ----------
        source : Path
            The original source path of the executable file to install.
        path : Path
            Relative path to the executable file to create beneath the state root.
        deadline : Deadline
            Maximum time in seconds to wait for required host commands.
        """
        await self._host_install(
            self.path(path),
            source,
            group=BERTRAND_GROUP,
            mode=self.bin_mode,
            deadline=deadline,
        )

    async def _render_tmpfs_systemd_unit(
        self,
        *,
        gid: int,
        deadline: Deadline,
    ) -> None:
        fd: int | None = None
        temp_unit: Path | None = None
        try:
            fd, name = tempfile.mkstemp(prefix="bertrand-runtime.", suffix=".mount")
            temp_unit = Path(name)
            os.write(
                fd,
                "\n".join(
                    (
                        "[Unit]",
                        "Description=Bertrand tmpfs runtime state",
                        "After=local-fs.target",
                        "",
                        "[Mount]",
                        "What=tmpfs",
                        f"Where={self.runtime}",
                        "Type=tmpfs",
                        (
                            f"Options=mode={self.dir_mode:o},uid=0,gid={gid},nosuid,"
                            "nodev,noexec"
                        ),
                        "",
                        "[Install]",
                        "WantedBy=multi-user.target",
                        "",
                    )
                ).encode("utf-8"),
            )
            os.fsync(fd)
            os.close(fd)
            fd = None
            await self._host_install(
                self.unit,
                temp_unit,
                mode=0o644,
                group="root",
                deadline=deadline,
            )
        finally:
            if fd is not None:
                with contextlib.suppress(OSError):
                    os.close(fd)
            if temp_unit is not None:
                temp_unit.unlink(missing_ok=True)

    async def init(self, *, deadline: Deadline, yes: bool) -> None:
        """Initialize Bertrand's host state directory scaffold.

        Parameters
        ----------
        deadline : Deadline
            Maximum time in seconds to wait for required host commands.
        yes : bool
            If True, automatically confirm any prompts for installing the file.

        Raises
        ------
        OSError
            If the host cannot support Bertrand's managed state layout.

        Notes
        -----
        When successful, this method will lock the `State` object's `lock` attribute as
        a side effect, in order to properly synchronize the global portion of the host
        bootstrap process.  The caller must immediately follow this method with a
        `try: ... finally: STATE.lock.unlock()` block to ensure the lock is properly
        released.
        """
        if inside_image():
            msg = "Bertrand state bootstrap cannot run from inside the cluster."
            raise OSError(msg)
        if os.name != "posix":
            msg = "Bertrand state bootstrap requires a POSIX host."
            raise OSError(msg)
        await _require_systemd(deadline)

        # prepare host prereqs + bertrand group before creating any state
        package_manager = PackageManager()
        await _install_prereqs(package_manager, deadline=deadline, yes=yes)
        group = await _create_bertrand_group(deadline=deadline, yes=yes)

        # acquire global init lock
        await self.lock.lock(deadline=deadline)
        try:
            # create state directories
            for path in (
                self.root,
                self.bin,
                self.cache,
                self.runtime,
                self.mount,
                self.mount_locks,
                self.kube.cache,
                self.kube.runtime,
                self.kube.lock.parent,
            ):
                await self.mkdir(path, deadline=deadline)

            # initialize state ID file if missing
            host_id = ""
            if self.id_file.exists():
                if not self.id_file.is_file():
                    msg = f"state id path exists but is not a file: {self.id_file}"
                    raise OSError(msg)
                with contextlib.suppress(ValueError, OSError):
                    host_id = uuid.UUID(
                        self.id_file.read_text(encoding="utf-8").strip()
                    ).hex
            if not host_id:
                await self.write(
                    self.id_file,
                    uuid.uuid4().hex + "\n",
                    deadline=deadline,
                )

            # render tmpfs systemd unit for runtime directory, then reload systemd
            await self._render_tmpfs_systemd_unit(gid=group.gr_gid, deadline=deadline)
            await run(
                sudo(["systemctl", "daemon-reload"], non_interactive=True),
                deadline=deadline,
            )
            await run(
                sudo(
                    ["systemctl", "enable", "--now", self.unit.name],
                    non_interactive=True,
                ),
                deadline=deadline,
            )

            # confirm runtime directory is properly mounted
            mount = HostMount.search(self.runtime)
            if mount is None or mount.fs_type.strip().lower() != "tmpfs":
                msg = (
                    f"failed to activate Bertrand tmpfs runtime mount at "
                    f"{self.path(self.runtime)}"
                )
                raise OSError(msg)
        except:
            await self.lock.unlock(ignore_errors=True)
            raise

    async def clean(self, *, deadline: Deadline) -> None:
        """Remove Bertrand's state directory and all its contents.

        Parameters
        ----------
        deadline : Deadline
            Maximum time in seconds to wait for required host commands.

        Raises
        ------
        OSError
            If the state root cannot be removed.
        """
        if inside_image():
            msg = "Bertrand state cleanup cannot run from inside the cluster."
            raise OSError(msg)

        # disable tmpfs unit for runtime directory
        systemctl = shutil.which("systemctl")
        if systemctl:
            await run(
                sudo([systemctl, "disable", "--now", self.unit.name]),
                check=False,
                capture_output=True,
                deadline=deadline,
            )
            await run(
                sudo(["rm", "-f", str(self.unit)]),
                check=False,
                capture_output=True,
                deadline=deadline,
            )
            await run(
                sudo([systemctl, "daemon-reload"]),
                check=False,
                capture_output=True,
                deadline=deadline,
            )

        if self.root.is_symlink() or self.root.is_file():
            msg = f"state root path is not a directory: {self.root}"
            raise OSError(msg)
        if not self.root.exists():
            return

        # remove and unmount all repositories mounted to this host
        if self.mount.exists():
            if not self.mount.is_dir():
                msg = f"repository mount catalog is not a directory: {self.mount}"
                raise OSError(msg)
            for repo_root in sorted(self.mount.iterdir()):
                if not repo_root.is_dir() or repo_root.is_symlink():
                    continue

                # delete all recognized aliases to each repository
                try:
                    repo = self.repo(repo_root.name)
                except ValueError:
                    continue
                async with repo.aliases(deadline=deadline) as aliases:
                    for alias in aliases.aliases.copy():
                        aliases.unlink(alias)

                # unmount repository volume
                mount = HostMount.search(repo.mount)
                if mount is not None:
                    await mount.unmount(deadline=deadline, force=True)

        # clean up any remaining mounts under the state directory
        mounts = sorted(
            HostMount.under(self.root),
            key=lambda item: (
                f"{len(item.mount_point.parts)}{item.mount_point.as_posix()}"
            ),
            reverse=True,
        )
        for mount in mounts:
            await mount.unmount(deadline=deadline, force=True)

        # confirm no residual mounts remain under the state directory
        residual = HostMount.under(self.root)
        if residual:
            msg = (
                "residual repository mounts remain:\n"
                f"{'\n'.join(sorted(str(m.mount_point) for m in residual))}"
            )
            raise OSError(msg)

        # remove the state root directory and all its contents
        try:
            shutil.rmtree(self.root)
        except OSError as err:
            msg = f"failed to remove state root directory at {self.root}"
            raise OSError(msg) from err
        if self.root.exists() or self.root.is_symlink():
            msg = f"state directory still exists after cleanup: {self.root}"
            raise OSError(msg)

    @dataclass(frozen=True)
    class Repository:
        """A simple structure describing local state metadata for a Bertrand repo.

        Attributes
        ----------
        state : State
            The parent `State` object that this repository belongs to, used to resolve
            paths and perform filesystem operations.
        root : Path
            Absolute path to the root of this repository's metadata directory under the
            state mount catalog.  This is not the same as the repository's mount point,
            which is where the repository's content is actually mounted to the host
            filesystem.
        mount : Path
            Absolute path to this repository's hidden mount point on the host, which is
            where the repository's content is actually mounted to the host filesystem.
        git : GitRepository
            A `GitRepository` instance rooted at this repository's mount point, for
            convenience.  Note that the underlying git repository is not guaranteed to
            be valid until `bertrand init` has completed successfully for this
            repository, and at least one reference to the repository remains alive on
            the host system.  Otherwise, the repository may be unmounted, and the
            corresponding Git repository will not be valid until the mount is restored.
        id_file : Path
            Absolute path to a file within this repository's metadata directory that
            contains the mounted repository's authoritative UUID, which is used to
            detect and repair mount-catalog drift.
        alias_file : Path
            Absolute path to this repository's alias ledger file, which contains a JSON
            array of absolute paths that are symlinked to this repository's mount point
            as aliases.
        lock : HostLock
            A host lock for synchronizing access to this repository's metadata and mount
            information across concurrent `bertrand init` commands.  The lock path is
            derived from the idempotent mount ID, and is stored in the tmpfs
            runtime directory to ensure it does not persist across reboots.
        """

        state: State = field(repr=False, compare=False)
        root: Path
        mount: Path
        git: GitRepository
        id_file: Path
        alias_file: Path
        lock: HostLock

        @property
        def mount_id(self) -> str:
            """The local hidden mount catalog ID.

            Returns
            -------
            str
                The UUID encoded by this repository's root directory name under the
                host-local mount catalog.
            """
            return self.root.name

        @property
        def repo_id(self) -> str | None:
            """Read the repository metadata ID stored inside the hidden mount.

            Returns
            -------
            str | None
                UUID hex string from the metadata file, or None when the file is
                absent.

            Raises
            ------
            OSError
                If the metadata path exists but is not a regular UTF-8 UUID file.
            """
            if not self.id_file.exists():
                return None
            if not self.id_file.is_file():
                msg = f"repository metadata identity path is not a file: {self.id_file}"
                raise OSError(msg)

            try:
                return uuid.UUID(self.id_file.read_text(encoding="utf-8").strip()).hex
            except (OSError, ValueError) as err:
                msg = f"repository metadata identity is invalid at {self.id_file}"
                raise OSError(msg) from err

        def path(self, path: Path) -> Path:
            """Return an absolute path under this repository's mount point.

            Parameters
            ----------
            path : Path
                A managed repo path to resolve.  If the path is relative, then it will
                be interpreted as relative to the repository's mount point.  If the path
                is absolute, then it will be used as-is.  In both cases, the normalized
                path must be contained within the repository's mount point.

            Returns
            -------
            Path
                Absolute path beneath this repository mount point.

            Raises
            ------
            ValueError
                If the path is not absolute or escapes the managed mount point.
            """
            if not path.is_absolute():
                path = self.mount / path
            path = path.resolve(strict=False)
            if not path.is_relative_to(self.mount):
                msg = f"repository path is not contained under {self.mount}: {path}"
                raise ValueError(msg)
            return path

        async def init(self, *, deadline: Deadline) -> None:
            """Create this repository's host-local catalog and mount point.

            Parameters
            ----------
            deadline : Deadline
                Maximum time in seconds to wait for required host commands.
            """
            await self.state.mkdir(self.root, deadline=deadline)
            await self.state.mkdir(self.mount, deadline=deadline)

        @dataclass
        class Aliases:
            """Async context manager for locked repository alias mutation."""

            repo: State.Repository
            deadline: Deadline
            aliases: set[Path] = field(default_factory=set)
            _depth: int = field(default=0, repr=False)

            def __post_init__(self) -> None:
                """Validate the alias manager deadline.

                Raises
                ------
                TimeoutError
                    If the deadline has already expired.
                """
                if self.deadline.remaining <= 0:
                    msg = "repository alias lock timeout must be positive"
                    raise TimeoutError(msg)

            async def __aenter__(self) -> Self:
                """Lock, load, and filter the host-local aliases for this repository.

                Returns
                -------
                State.Repository.Aliases
                    Active alias mutation context.

                Raises
                ------
                OSError
                    If the alias ledger file is present but cannot be read.
                TypeError
                    If the alias ledger file contains unexpected data.
                """
                if self._depth > 0:
                    self._depth += 1
                    return self  # re-entrant case

                # acquire lock
                require_bertrand_group()
                self.aliases.clear()
                await self.repo.lock.lock(deadline=self.deadline)
                try:
                    if self.repo.alias_file.exists():
                        try:
                            payload = json.loads(
                                self.repo.alias_file.read_text(encoding="utf-8")
                            )
                        except json.JSONDecodeError as err:
                            msg = (
                                f"repository alias ledger at {self.repo.alias_file} "
                                "does not contain valid JSON data"
                            )
                            raise TypeError(msg) from err
                        except OSError as err:
                            msg = (
                                "failed to read repository alias ledger at "
                                f"{self.repo.alias_file}"
                            )
                            raise OSError(msg) from err
                        if not isinstance(payload, list):
                            msg = (
                                f"expected a JSON array of alias paths, got: {payload}"
                            )
                            raise TypeError(msg)

                        for path in payload:
                            if not isinstance(path, str):
                                msg = f"expected alias paths to be strings, got: {path}"
                                raise TypeError(msg)
                            path = Path(path)
                            if not path.is_absolute():
                                msg = f"expected absolute alias paths, got: {path}"
                                raise TypeError(msg)

                            # only retain aliases that are still valid symlinks to this
                            # repo's mount point
                            if path.is_symlink() and symlink_points_to(
                                path,
                                self.repo.mount,
                            ):
                                self.aliases.add(path)
                except:
                    await self.repo.lock.unlock(ignore_errors=True)
                    raise

                self._depth = 1
                return self

            async def __aexit__(
                self,
                exc_type: type[BaseException] | None,
                exc_value: BaseException | None,
                traceback: TracebackType | None,
            ) -> None:
                """Dump the aliases back to disk and release the repository lock.

                Parameters
                ----------
                exc_type : type[BaseException] | None
                    The exception type if an exception was raised in the context block,
                    otherwise None.
                exc_value : BaseException | None
                    The exception value if an exception was raised in the context block,
                    otherwise None.
                traceback : TracebackType | None
                    The traceback if an exception was raised in the context block,
                    otherwise None.
                """
                if self._depth > 1:
                    self._depth -= 1
                    return  # re-entrant case

                self._depth = 0
                ignore_errors = exc_value is not None
                try:
                    # dump aliases to disk
                    await self.repo.state.mkdir(
                        self.repo.alias_file.parent,
                        deadline=self.deadline,
                    )
                    await self.repo.state.write(
                        self.repo.alias_file,
                        json.dumps(
                            sorted(str(alias) for alias in self.aliases),
                            separators=(",", ":"),
                        )
                        + "\n",
                        deadline=self.deadline,
                    )
                except:  # noqa: E722
                    if not ignore_errors:  # do not mask original exception
                        ignore_errors = True  # ignore subsequent unlock errors
                        raise
                finally:
                    await self.repo.lock.unlock(ignore_errors=ignore_errors)

            def _assert_active_context(self, action: str) -> None:
                if self._depth < 1:
                    msg = (
                        "Repository.Aliases must be used inside 'async with' before "
                        f"calling {action}()"
                    )
                    raise RuntimeError(msg)

            def link(self, path: Path) -> bool:
                """Create or validate a managed alias symlink for this repository.

                Parameters
                ----------
                path : Path
                    Absolute path to create a symlink to this repository's mount point
                    at.

                Returns
                -------
                bool
                    True if a new symlink was created, false if it already existed.

                Raises
                ------
                OSError
                    If the alias path collides with unmanaged content.
                """
                self._assert_active_context("link")
                path = abspath(path)
                missing = not (path.exists() or path.is_symlink())
                if missing:
                    atomic_symlink(self.repo.mount, path)
                elif not symlink_points_to(path, self.repo.mount):
                    msg = (
                        f"repository alias path '{path}' already exists and is not a "
                        f"managed symlink to '{self.repo.mount}'"
                    )
                    raise OSError(msg)
                self.aliases.add(path)
                return missing

            def unlink(self, path: Path) -> bool:
                """Remove a managed alias symlink for this repository.

                Parameters
                ----------
                path : Path
                    Absolute path to remove from this repository's aliases.

                Returns
                -------
                bool
                    True if the alias was removed or discarded from this context, false
                    otherwise.
                """
                self._assert_active_context("unlink")
                path = abspath(path)

                remove = symlink_points_to(path, self.repo.mount)
                if remove:
                    path.unlink()

                n = len(self.aliases)
                self.aliases.discard(path)
                return remove or len(self.aliases) < n

            def transfer(self, target: State.Repository.Aliases) -> int:
                """Transfer active aliases from this repository to another.

                Parameters
                ----------
                target : State.Repository.Aliases
                    Active alias context that should receive this context's aliases.

                Returns
                -------
                int
                    Number of live aliases transferred to the target context.
                """
                self._assert_active_context("transfer")
                target._assert_active_context("transfer")
                if self is target or self.repo.mount == target.repo.mount:
                    return 0

                # loop over all recorded aliases to the source repository and discard
                # or retarget them to the new repository
                moves = 0
                for alias in sorted(self.aliases):
                    if symlink_points_to(alias, self.repo.mount):
                        atomic_symlink(alias, target.repo.mount)
                        target.aliases.add(alias)
                        moves += 1
                    self.aliases.discard(alias)

                return moves

        def aliases(self, *, deadline: Deadline) -> Aliases:
            """Return a locked alias symlink mutation context for this repository.

            Parameters
            ----------
            deadline : Deadline
                Maximum time in seconds to wait for the alias mutation lock.

            Returns
            -------
            State.Repository.Aliases
                Async context manager for repository alias mutation.
            """
            return self.Aliases(self, deadline=deadline)

        async def _normalize(
            self,
            *,
            deadline: Deadline,
            visited: set[str],
        ) -> State.Repository:
            # check for cycles
            if self.mount_id in visited:
                msg = (
                    "repository metadata normalization cycle detected: "
                    f"{' -> '.join((*visited, self.mount_id))}"
                )
                raise OSError(msg)
            visited.add(self.mount_id)

            # try to read repository ID from metadata and repair/reuse it if it matches
            # the mount ID
            repo_id = self.repo_id
            if repo_id is None:
                await self.state.write(
                    self.id_file,
                    self.mount_id + "\n",
                    deadline=deadline,
                )
                return self
            if repo_id == self.mount_id:
                return self
            if (
                not self.root.exists()
                or not self.root.is_dir()
                or self.root.is_symlink()
            ):
                msg = f"cannot repair missing repository catalog path: {self.root}"
                raise OSError(msg)

            # repo ID doesn't match mount ID; treat repo ID as authoritative and move
            # aliases to that location, leaving any required remount to the Ceph layer
            target = self.state.repo(repo_id)
            if (target.root.exists() or target.root.is_symlink()) and (
                target.root.is_symlink() or not target.root.is_dir()
            ):
                msg = (
                    f"cannot repair repository catalog {self.root}: authoritative "
                    f"repository id {repo_id} maps to malformed path {target.root}"
                )
                raise OSError(msg)

            # recur only through mounted targets; missing/unmounted authoritative
            # mounts are valid dangling resurrection targets for the Ceph layer
            result = target
            if HostMount.search(target.mount) is not None:
                result = await target._normalize(deadline=deadline, visited=visited)

            # lock in deterministic order to prevent deadlocks
            if self.mount_id < result.mount_id:
                async with (
                    self.aliases(deadline=deadline) as source_aliases,
                    result.aliases(deadline=deadline) as target_aliases,
                ):
                    source_aliases.transfer(target_aliases)
            else:
                async with (
                    result.aliases(deadline=deadline) as target_aliases,
                    self.aliases(deadline=deadline) as source_aliases,
                ):
                    source_aliases.transfer(target_aliases)

            # explicitly unmount source after transferring aliases so as not to
            # interfere with any recursive ancestors; the Ceph layer will resurrect the
            # mount at the correct location if needed using the updated mount ID
            mount = HostMount.search(self.mount)
            if mount is not None:
                await mount.unmount(deadline=deadline, force=False)
            return result

        async def normalize(self, *, deadline: Deadline) -> State.Repository:
            """Ensure this repository's local mount ID agrees with mounted metadata.

            Parameters
            ----------
            deadline : Deadline
                Maximum time in seconds to wait for required host commands.

            Returns
            -------
            State.Repository
                Repository layout for the authoritative metadata ID.
            """
            return await self._normalize(deadline=deadline, visited=set())

        async def gc(self, *, deadline: Deadline) -> bool:
            """Prune this repository's safe host-local mount residue.

            Parameters
            ----------
            deadline : Deadline
                Overall deadline for pruning host-local residue.

            Returns
            -------
            bool
                True if a hidden mount or empty catalog root was removed.
            """
            # skip this repository if we can't immediately acquire its lock
            if not await self.lock.try_lock():
                return False

            # load the live aliases for this repository and skip if any are present
            ignore_errors = False
            try:
                async with self.aliases(deadline=deadline) as aliases:
                    if aliases.aliases:
                        return False

                # otherwise, if there are no active aliases, attempt to unmount the
                # repository
                mount = HostMount.search(self.mount)
                if mount is not None:
                    try:
                        await mount.unmount(deadline=deadline, force=False)
                    except OSError:
                        return False

                # remove the repository entry
                shutil.rmtree(self.root)
            except:
                ignore_errors = True
                raise
            finally:
                await self.lock.unlock(ignore_errors=ignore_errors)

            return True

    def repo(self, mount_id: str) -> State.Repository:
        """Get the local state layout for one repository mount catalog entry.

        Parameters
        ----------
        mount_id : str
            UUID encoded by the repository's host-local catalog directory.

        Returns
        -------
        State.Repository
            Pure repository layout for the requested mount catalog ID.

        Raises
        ------
        ValueError
            If the provided mount catalog ID is not a valid UUID string.
        """
        try:
            mount_id = uuid.UUID(mount_id).hex
        except ValueError as err:
            msg = f"invalid repository mount id (must be a valid UUID): {mount_id}"
            raise ValueError(msg) from err

        root = self.mount / mount_id
        return self.Repository(
            state=self,
            root=root,
            mount=root / "mount",
            git=GitRepository(self.mount / ".git"),
            id_file=root / "mount" / METADATA_ID,
            alias_file=root / "aliases.json",
            lock=HostLock(self.mount_locks / f"{mount_id}.lock"),
        )

    def resolve_alias(self, path: Path) -> tuple[Path, State.Repository] | None:
        """Return the nearest managed alias at or above `path`, if any.

        Parameters
        ----------
        path : Path
            Path whose ancestors should be checked for managed repository aliases.

        Returns
        -------
        tuple[Path, State.Repository] | None
            Alias path and catalog repository object, otherwise None.

        Raises
        ------
        OSError
            If a candidate symlink points into Bertrand's repository catalog but
            does not match the expected hidden mount layout.
        """
        path = abspath(path)
        for candidate in (path, *path.parents):
            # skip non-symlink components
            if not candidate.is_symlink():
                continue

            # if a symlink points into the mount catalog, it may be a managed alias
            try:
                target = candidate.readlink()
            except OSError as err:
                msg = f"failed to read target for link at {candidate}: {err}"
                raise OSError(msg) from err
            if not target.is_absolute():
                continue
            try:
                relative = target.relative_to(self.mount)
            except ValueError:
                continue

            # if the target conforms to the expected structure and has a proper mount ID
            if len(relative.parts) == 2 and relative.parts[1] == "mount":
                with contextlib.suppress(ValueError):
                    return candidate, self.repo(relative.parts[0])
            msg = (
                f"repository alias path {candidate} points to malformed target "
                f"{target}; expected {self.mount}/<repo_id>/mount"
            )
            raise OSError(msg)

        # no managed alias found among path ancestors
        return None

    async def gc(
        self,
        *,
        deadline: Deadline,
        limit: int | None,
    ) -> list[State.Repository]:
        """Prune bounded host-local hidden repository mounts with no live aliases.

        Parameters
        ----------
        deadline : Deadline
            Overall deadline for the bounded GC pass.
        limit : int | None
            Maximum number of repository mount entries to inspect.  Zero disables
            pruning.  None leads to unbounded GC, which checks all repository mounts on
            the local system, and may be less efficient when there are many mounts.

        Returns
        -------
        list[State.Repository]
            Repository mount objects whose hidden mounts or empty catalog roots were
            removed.

        Raises
        ------
        ValueError
            If `limit` is negative.
        """
        if limit is not None:
            if limit < 0:
                msg = "repository mount prune limit cannot be negative"
                raise ValueError(msg)
            if limit == 0:
                return []
        if not self.mount.exists():
            return []

        # gather all repository mounts on the local system in deterministic order
        mounts: list[State.Repository] = []
        with contextlib.suppress(OSError):
            for child in sorted(self.mount.iterdir()):
                if child.is_dir() and not child.is_symlink():
                    # only consider directories with valid UUID names
                    with contextlib.suppress(ValueError):
                        mounts.append(self.repo(child.name))

        # extract a rotating, random slice of mounts to include in this GC pass
        if limit is not None and len(mounts) > limit:
            p = secrets.randbelow(len(mounts))
            q = (p + limit) % len(mounts)
            mounts = mounts[p:q] if p < q else mounts[p:] + mounts[:q]

        # delegate to repository-level GC method
        return [repo for repo in mounts if await repo.gc(deadline=deadline)]


STATE = State()
_HOOK_OPERATION_ERRORS: tuple[type[Exception], ...] = (
    OSError,
    RuntimeError,
    TimeoutError,
    ValueError,
    CommandError,
)


@dataclass(frozen=True)
class GitRepository:
    """An object-oriented wrapper around a Git repository.

    Attributes
    ----------
    git_dir : Path, optional
        The path to the repository's .git directory.  If omitted, the repository will
        be by running `git rev-parse --git-common-dir` in the current working
        directory.
    """

    @dataclass(frozen=True)
    class RefUpdate:
        """A single reference update received from git on stdin."""

        old: str
        new: str
        ref: str

        @property
        def is_head(self) -> bool:
            """Return whether this update targets a branch ref.

            Returns
            -------
            bool
                True if this update targets `refs/heads/*`.
            """
            return self.ref.startswith(GIT_REF_HEADS_PREFIX)

        @property
        def branch(self) -> str:
            """Return the short branch name for this update.

            Returns
            -------
            str
                The short branch name for `refs/heads/*` updates.
            """
            return self.ref[len(GIT_REF_HEADS_PREFIX) :]

        @property
        def created(self) -> bool:
            """Return whether this update created a ref.

            Returns
            -------
            bool
                True if this update created a new ref.
            """
            return all(c == "0" for c in self.old) and any(c != "0" for c in self.new)

        @property
        def destroyed(self) -> bool:
            """Return whether this update deleted a ref.

            Returns
            -------
            bool
                True if this update deleted an existing ref.
            """
            return any(c != "0" for c in self.old) and all(c == "0" for c in self.new)

        @classmethod
        def parse(cls, stdin: str) -> list[GitRepository.RefUpdate]:
            """Parse and validate transaction update lines from stdin.

            Parameters
            ----------
            stdin : str
                The raw stdin input containing reference update lines, typically read
                from the `reference-transaction` hook's standard input stream.

            Returns
            -------
            list[GitRepository.RefUpdate]
                A list of parsed reference updates.

            Raises
            ------
            ValueError
                If any line is malformed.
            """
            updates: list[GitRepository.RefUpdate] = []
            for index, raw in enumerate(stdin.splitlines(), start=1):
                line = raw.strip()
                if not line:
                    continue
                parts = line.split()
                if len(parts) != 3:
                    msg = (
                        f"malformed git transaction line {index}: expected "
                        f"'<old> <new> <ref>', got: {raw!r}"
                    )
                    raise ValueError(msg)
                old, new, ref = (part.strip() for part in parts)
                if not ref:
                    msg = (
                        f"malformed git transaction line {index}: ref must not be empty"
                    )
                    raise ValueError(msg)
                updates.append(cls(old=old, new=new, ref=ref))
            return updates

    @dataclass(frozen=True)
    class Worktree:
        """A parsed entry from `git worktree list --porcelain`.

        Attributes
        ----------
        path : Path
            The absolute path to the worktree checkout.
        branch : str | None
            The short branch name if this worktree is attached to `refs/heads/*`,
            otherwise None.
        """

        repo: GitRepository
        path: Path
        branch: str | None = None

        @property
        def id(self) -> str:
            """Ensure a checked-out worktree has a stable Bertrand UUID.

            Returns
            -------
            str
                Existing or newly generated UUID hex string.

            Raises
            ------
            FileNotFoundError
                If the worktree path does not exist.
            NotADirectoryError
                If the worktree path is not a directory.
            OSError
                If the worktree ID file exists, but is not a UTF-8 text file containing
                a valid UUID hex.
            """
            if not self.path.exists():
                msg = f"worktree path does not exist: {self.path}"
                raise FileNotFoundError(msg)
            if not self.path.is_dir():
                msg = f"worktree path is not a directory: {self.path}"
                raise NotADirectoryError(msg)

            # read an existing worktree ID if possible
            path = self.path / METADATA_ID
            if path.exists():
                if not path.is_file():
                    msg = f"Bertrand worktree identity path is not a file: {path}"
                    raise OSError(msg)
                text = path.read_text(encoding="utf-8").strip()
                return uuid.UUID(text).hex

            # generate a new worktree ID and write it atomically
            worktree_id = uuid.uuid4().hex
            atomic_write_text(path, f"{worktree_id}\n", encoding="utf-8")
            return worktree_id

        def __post_init__(self) -> None:
            """Canonicalize the worktree path and validate it exists as a directory.

            Raises
            ------
            FileNotFoundError
                If the worktree path does not exist.
            NotADirectoryError
                If the worktree path is not a directory.
            """
            object.__setattr__(self, "path", self.path.expanduser().resolve())
            if not self.path.exists():
                msg = f"worktree path does not exist: {self.path}"
                raise FileNotFoundError(msg)
            if not self.path.is_dir():
                msg = f"worktree path is not a directory: {self.path}"
                raise NotADirectoryError(msg)

        def _clean_worktree_parents(self) -> None:
            # clean up now-empty parent directories up to project root to account for
            # branch names that contain path separators
            cursor = self.path.parent
            while cursor != self.repo.root:
                try:
                    if any(cursor.iterdir()):
                        break
                    cursor.rmdir()
                except OSError:
                    break
                cursor = cursor.parent

        async def _worktree_belongs_to_repo(
            self, *, env: dict[str, str], deadline: Deadline
        ) -> bool:
            result = await run(
                ["git", "-C", str(self.path), "rev-parse", "--git-common-dir"],
                check=False,
                capture_output=True,
                env=env,
                deadline=deadline,
            )
            if result.returncode != 0:
                return False
            owner = Path(result.stdout.strip()).expanduser()
            if not owner.is_absolute():
                owner = self.path / owner
            return self.repo.git_dir == owner.expanduser().resolve()

        async def move(
            self,
            target: Path | None = None,
            *,
            deadline: Deadline = NO_DEADLINE,
        ) -> None:
            """Move this worktree to a different location.

            Parameters
            ----------
            target : Path | None, optional
                The destination path for the worktree.  If None, the worktree will be
                moved to its default location based on the branch name, if it is not
                already there.  Defaults to None.
            deadline : Deadline, optional
                An overall deadline by which the move must complete before raising a
                `TimeoutError`.  Defaults to an infinite deadline, which causes the
                command to block indefinitely until completion.  If the deadline is
                earlier than the time this method is called, a `TimeoutError` will be
                raised immediately.

            Raises
            ------
            ValueError
                If the target path cannot be determined for a branchless worktree, or
                if the target path is the same as the current path.
            FileExistsError
                If the target path already exists, and is not the same as the source
                path.
            """
            if target is None:
                if self.branch is None:
                    msg = (
                        "cannot determine default worktree target path for branchless "
                        "worktree; specify an explicit target path to move this "
                        "worktree"
                    )
                    raise ValueError(msg)
                target = self.repo.root / self.branch
            if target == self.path:
                return
            if target.exists():
                msg = f"target path already exists: {target}"
                raise FileExistsError(msg)

            target.parent.mkdir(parents=True, exist_ok=True)
            await self.repo.run(
                ["worktree", "move", "--relative-paths", str(self.path), str(target)],
                capture_output=True,
                deadline=deadline,
            )
            self._clean_worktree_parents()
            object.__setattr__(self, "path", target)

        async def destroy(self, *, deadline: Deadline = NO_DEADLINE) -> bool:
            """Destroy this worktree if it exists and is clean.

            Parameters
            ----------
            deadline : Deadline, optional
                An overall deadline by which the destruction must complete before
                raising a `TimeoutError`.  Defaults to an infinite deadline, which
                causes the command to block indefinitely until completion.  If the
                deadline is earlier than the time this method is called, a
                `TimeoutError` will be raised immediately.

            Returns
            -------
            bool
                True if the worktree was successfully destroyed or did not exist, false
                if the worktree exists but could not be destroyed due to dirty state.

            Raises
            ------
            RuntimeError
                If the target path does not belong to this repository.
            """
            # verify that the worktree is clean and objectively belongs to this
            # repository before attempting deletion
            env = await self.repo._strip_env(deadline=deadline)
            if not await self._worktree_belongs_to_repo(env=env, deadline=deadline):
                msg = f"worktree path does not belong to this repository: {self.path}"
                raise RuntimeError(msg)
            clean = await run(
                ["git", "-C", str(self.path), "status", "--porcelain"],
                capture_output=True,
                env=env,
                deadline=deadline,
            )
            if clean.stdout.strip():
                return False

            # remove the worktree using git, which will also properly clean up the
            # associated gitdir and any linked metadata
            await self.repo.run(
                ["worktree", "remove", str(self.path)],
                capture_output=True,
                deadline=deadline,
            )
            self._clean_worktree_parents()
            return True

    git_dir: Path

    @property
    def root(self) -> Path:
        """Return the repository root.

        Returns
        -------
        Path
            The absolute path to the repository's root directory, which is the parent of
            the .git directory.
        """
        return self.git_dir.parent

    @property
    def metadata_id(self) -> str | None:
        """Read the Bertrand repository identity stored in repository metadata.

        Returns
        -------
        str | None
            UUID hex string from `.bertrand/id`, or None when the metadata file is
            absent.

        Raises
        ------
        OSError
            If the metadata path exists but is not a regular UTF-8 UUID file.
        """
        id_file = self.root / METADATA_ID
        if not id_file.exists():
            return None
        if not id_file.is_file():
            msg = f"Bertrand repository identity path is not a file: {id_file}"
            raise OSError(msg)
        try:
            return uuid.UUID(id_file.read_text(encoding="utf-8").strip()).hex
        except (OSError, ValueError) as err:
            msg = f"Bertrand repository identity is invalid at {id_file}"
            raise OSError(msg) from err

    @property
    def path_id(self) -> str:
        """Return this repository's deterministic host/path identity.

        Returns
        -------
        str
            UUID5 hex string derived from the Bertrand host identity and repository
            root path.

        Raises
        ------
        OSError
            If Bertrand's host identity is missing or malformed. Run `bertrand init`
            to converge host state before resolving unmanaged repository identities.

        """
        try:
            host_id = uuid.UUID(STATE.id)
        except (OSError, ValueError) as err:
            msg = (
                "Bertrand host identity is missing or malformed. Run `bertrand init` "
                "to converge host state before resolving unmanaged repository IDs."
            )
            raise OSError(msg) from err
        return uuid.uuid5(host_id, self.root.as_posix()).hex

    @property
    def id(self) -> str:
        """Return the stable Bertrand repository identity.

        Returns
        -------
        str
            Metadata repository UUID when present, otherwise this repository's
            deterministic host/path UUID.
        """
        return self.metadata_id or self.path_id

    def __post_init__(self) -> None:
        """Automatically canonicalize the git_dir path."""
        object.__setattr__(self, "git_dir", self.git_dir.expanduser().resolve())

    @classmethod
    async def discover(
        cls,
        path: Path | None = None,
        *,
        deadline: Deadline = NO_DEADLINE,
    ) -> GitRepository | None:
        """Discover the Git repository for the current working directory.

        Parameters
        ----------
        path : Path | None, optional
            An optional path to use as the starting point for discovery.  If None (the
            default), then the current working directory will be used instead.
        deadline : Deadline, optional
            An overall deadline by which the discovery must complete before raising a
            `TimeoutError`.  Defaults to an infinite deadline, which causes the command
            to block indefinitely until completion.  If the deadline is earlier than the
            time this method is called, a `TimeoutError` will be raised immediately.

        Returns
        -------
        GitRepository | None
            The discovered Git repository, assuming a `path` is inside a Git repository
        """
        result = await run(
            ["git", "rev-parse", "--path-format=absolute", "--git-common-dir"],
            cwd=path,
            check=False,
            capture_output=True,
            deadline=deadline,
        )
        if result.returncode == 0:
            return cls(git_dir=Path(result.stdout.strip()))
        return None

    @classmethod
    async def resolve(
        cls,
        path: Path,
        *,
        deadline: Deadline = NO_DEADLINE,
    ) -> tuple[GitRepository, GitRepository.Worktree | None]:
        """Resolve a repository and worktree path.

        Parameters
        ----------
        path : Path
            The input path to resolve a repository and worktree for.  The ancestors
            will be scanned to find the nearest git repository, and the remaining path
            components will be treated as a relative worktree path within the
            repository.  If no repository is found, then the input path will be
            treated as an uninitialized repository with repository-level scope.  If
            the path leads to a bare repository, then non-root targets must match a
            registered worktree root exactly.
        deadline : Deadline, optional
            An overall deadline by which the resolution must complete before raising a
            `TimeoutError`.  Defaults to an infinite deadline, which causes the command
            to block indefinitely until completion.  If the deadline is earlier than the
            time this method is called, a `TimeoutError` will be raised immediately.

        Returns
        -------
        tuple[GitRepository, GitRepository.Worktree | None]
            A tuple containing the resolved Git repository and an explicit registered
            worktree, if the input path targets one.  The worktree is None for
            repository-level targets and uninitialized repositories.  Note that the
            `GitRepository` may be uninitialized if no existing repository was found
            during resolution.

        Raises
        ------
        OSError
            If the resolved repository is bare and does not support relative paths,
            or if a non-root target is not registered as a worktree of the resolved
            repository.
        """
        repo = await cls.discover(path, deadline=deadline)

        # new bare repository
        if repo is None:
            if not await cls.supports_relative_paths(deadline=deadline):
                raise OSError(GIT_REQUIRE_RELATIVE_PATHS)
            repo = cls(path / ".git")
            return repo, None

        # existing bare repository
        if await repo.bare():
            if not await cls.supports_relative_paths(deadline=deadline):
                raise OSError(GIT_REQUIRE_RELATIVE_PATHS)
            worktree = path.relative_to(repo.root)
            if not worktree.parts:
                return repo, None
            match = next(
                (
                    wt
                    for wt in await repo.worktrees(deadline=deadline)
                    if wt.path == path
                ),
                None,
            )
            if match is None:
                msg = (
                    f"worktree at {worktree} is not registered as a git worktree of "
                    f"bare repository: {repo.root}"
                )
                raise OSError(msg)
            return repo, match

        # existing non-bare repository
        worktree = path.relative_to(repo.root)
        if not worktree.parts:
            return repo, None
        match = next(
            (wt for wt in await repo.worktrees(deadline=deadline) if wt.path == path),
            None,
        )
        if match is None:
            msg = (
                f"nested worktree at {worktree} is not registered as a git worktree "
                f"of non-bare repository: {repo.root}"
            )
            raise OSError(msg)
        return repo, match

    def __hash__(self) -> int:
        """Allow GitRepositories to be hashed according to their logical identity.

        Returns
        -------
        int
            A hash derived from the repository's `id`, which will be regenerated if it
            is missing.
        """
        return hash(self.id)

    def __eq__(self, other: object) -> bool:
        """Compare GitRepositories based on their logical identity.

        Parameters
        ----------
        other : object
            Object to compare against this repository.

        Returns
        -------
        bool | NotImplemented
            True if `other` is a GitRepository with the same `id` as this one, or
            NotImplemented if `other` is not a GitRepository.  If either repository's
            `id` is missing, it will be regenerated.
        """
        if isinstance(other, GitRepository):
            return self.id == other.id
        return NotImplemented

    async def _strip_env(self, *, deadline: Deadline) -> dict[str, str]:
        env = os.environ.copy()
        local = await self.run(
            ["rev-parse", "--local-env-vars"],
            check=False,
            capture_output=True,
            env=env,
            deadline=deadline,
        )
        if local.returncode == 0:
            keys = [key.strip() for key in local.stdout.splitlines() if key.strip()]
        else:
            keys = [
                "GIT_DIR",
                "GIT_WORK_TREE",
                "GIT_COMMON_DIR",
            ]  # best-effort fallback
        for key in keys:
            env.pop(key, None)
        return env

    async def exists(self, *, deadline: Deadline = NO_DEADLINE) -> bool:
        """Return whether this repository is a valid, initialized repository.

        Parameters
        ----------
        deadline : Deadline, optional
            An overall deadline by which the validation must complete before raising a
            `TimeoutError`.  Defaults to an infinite deadline, which causes the command
            to block indefinitely until completion.  If the deadline is earlier than the
            time this method is called, a `TimeoutError` will be raised immediately.

        Returns
        -------
        bool
            True if this repository has been initialized, or False if it has not.
        """
        return (
            self.git_dir.exists()
            and self.git_dir.is_dir()
            and (
                await self.run(
                    ["rev-parse", "--git-dir"],
                    check=False,
                    capture_output=True,
                    deadline=deadline,
                )
            ).returncode
            == 0
        )

    async def init(
        self,
        *,
        branch: str | None = None,
        bare: bool = True,
        deadline: Deadline = NO_DEADLINE,
    ) -> None:
        """Initialize a new Git repository at the given path.

        Parameters
        ----------
        branch : str | None, optional
            An optional initial branch name to use for the repository.  If None (the
            default), then the Git installation's default branch will be used (e.g.
            "master" or "main").
        bare : bool, optional
            Whether to create a bare repository (default is True).  If false, then a
            standard repository with a working tree will be created instead.
        deadline : Deadline, optional
            An overall deadline by which the initialization must complete before raising
            a `TimeoutError`.  Defaults to an infinite deadline, which causes the
            command to block indefinitely until completion.  If the deadline is earlier
            than the time this method is called, a `TimeoutError` will be raised
            immediately.
        """
        self.git_dir.mkdir(parents=True, exist_ok=True)
        cmd = ["git", "init", "--quiet"]
        if branch is not None:
            cmd.extend(["--initial-branch", branch])
        if bare:
            cmd.append("--bare")
        cmd.append(str(self.git_dir))
        await run(cmd, deadline=deadline)

    async def mirror_from(
        self,
        source: GitRepository,
        *,
        deadline: Deadline = NO_DEADLINE,
    ) -> None:
        """Converge this repository from a source using mirror semantics.

        This is a repository-convergence helper, not a generic clone API. It performs
        first-time mirror initialization when the destination is uninitialized, and
        subsequent full-ref mirror updates on reruns.

        Parameters
        ----------
        source : GitRepository
            Source repository whose refs/object graph should be mirrored.
        deadline : Deadline, optional
            An overall deadline by which the operation must complete before raising
            a `TimeoutError`.  Defaults to an infinite deadline, which causes the
            command to block indefinitely until completion.  If the deadline is earlier
            than the time this method is called, a `TimeoutError` will be raised
            immediately.

        Raises
        ------
        OSError
            If the source repository has not been initialized.
        """
        if not await source.exists(deadline=deadline):
            msg = (
                f"cannot mirror from uninitialized source repository: {source.git_dir}"
            )
            raise OSError(msg)

        # if this is a fresh repository, just clone directly to initialize it
        if not await self.exists(deadline=deadline):
            await run(
                [
                    "git",
                    "clone",
                    "--mirror",
                    str(source.root),
                    str(self.git_dir),
                ],
                capture_output=True,
                deadline=deadline,
            )

        # otherwise, fetch and mirror all refs to converge with the source repository
        else:
            await self.run(
                [
                    "fetch",
                    "--prune",
                    str(source.root),
                    "+refs/*:refs/*",
                ],
                capture_output=True,
                deadline=deadline,
            )

    async def run(
        self,
        argv: list[str],
        *,
        check: bool = True,
        capture_output: bool | None = False,
        input: str | None = None,  # noqa: A002
        deadline: Deadline = NO_DEADLINE,
        attempts: int = 1,
        delay: float = 0.0,
        cwd: Path | None = None,
        env: Mapping[str, str] | None = None,
    ) -> CompletedProcess:
        """Run a asynchronous git command against this repository.

        Parameters
        ----------
        argv : list[str]
            The command and its arguments to run, excluding the initial "git".
        check : bool, optional
            Whether to raise a `CommandError` if the command fails (default is True).
            If false, then any errors will be ignored.
        capture_output : bool | None, optional
            If true, then all output will be redirected to the returned
            `CompletedProcess` or `CommandError`, and excluded from the inherited
            stdout/stderr streams.  If false (the default), then the opposite is the
            case, and the returned `CompletedProcess` or `CommandError` will not
            include any captured output.  If None, then output will be "tee'd" to both
            the console and the returned objects simultaneously.  Note that teeing
            output in this way may break TTY behavior for some commands, and is not
            recommended for interactive use.
        input : str | None, optional
            Input to send to the command's stdin (default is None).
        deadline : Deadline, optional
            An overall deadline by which the command must complete before raising a
            `TimeoutExpired` exception.  Defaults to an infinite deadline, which causes
            the command to block indefinitely until completion.  If the deadline is
            earlier than the time this method is called, then a `TimeoutExpired`
            exception will be raised immediately.
        attempts : int, optional
            The total number of times to attempt the command.  Defaults to 1, which
            means no retries.  If greater than 1, then any command that exits with a
            nonzero exit code will be re-run after a short delay, up to the specified
            number of times in total.
        delay : float, optional
            The delay in seconds to wait between retries when `attempts` is greater than
            1.  Default is zero, which yields to the event loop before retrying.  Must
            be non-negative.
        cwd : Path | None, optional
            An optional working directory to run the command in.  If None (the default),
            then the current working directory will be used.
        env : Mapping[str, str] | None, optional
            An optional environment dictionary to use for the command.  If None (the
            default), then the current process's environment will be used.

        Returns
        -------
        CompletedProcess
            The completed process result.
        """
        return await run(
            ["git", "--git-dir", str(self.git_dir), *argv],
            check=check,
            capture_output=capture_output,
            input=input,
            deadline=deadline,
            attempts=attempts,
            delay=delay,
            cwd=cwd,
            env=env,
        )

    async def dirty(self, *, deadline: Deadline = NO_DEADLINE) -> bool:
        """Check whether this repository has uncommitted changes.

        Parameters
        ----------
        deadline : Deadline, optional
            An overall deadline by which the check must complete before raising a
            `TimeoutError`.  Defaults to an infinite deadline, which causes the command
            to block indefinitely until completion.  If the deadline is earlier than the
            time this method is called, a `TimeoutError` will be raised immediately.

        Returns
        -------
        bool
            `True` if any checked-out worktree for this repository has uncommitted
            changes, or `False` otherwise. Non-bare repositories are checked directly
            at `self.root`. Bare repositories are checked by scanning every registered
            worktree. Bare repositories with zero worktrees are considered clean.

        """
        if not await self.bare(deadline=deadline):
            result = await self.run(
                ["status", "--porcelain"],
                capture_output=True,
                cwd=self.root,
                deadline=deadline,
            )
            return bool(result.stdout.strip())

        # Bare repositories do not have their own worktree; check each attached
        # worktree under a sanitized git environment instead.
        env = await self._strip_env(deadline=deadline)
        for wt in await self.worktrees(deadline=deadline):
            result = await run(
                ["git", "-C", str(wt.path), "status", "--porcelain"],
                capture_output=True,
                env=env,
                deadline=deadline,
            )
            if result.stdout.strip():
                return True
        return False

    async def git_path(
        self,
        path: Path,
        *,
        cwd: Path | None = None,
        deadline: Deadline = NO_DEADLINE,
    ) -> Path:
        """Resolve a git-path using `git rev-parse --git-path`.

        Parameters
        ----------
        path : str
            The git-path expression to resolve (e.g. `hooks/pre-commit`).
        cwd : Path | None, optional
            Optional working directory for relative path resolution semantics.
        deadline : Deadline
            An overall deadline by which the resolution must complete before raising a
            `TimeoutError`.  Defaults to an infinite deadline, which causes the command
            to block indefinitely until completion.  If the deadline is earlier than the
            time this method is called, a `TimeoutError` will be raised immediately.

        Returns
        -------
        Path
            The resolved absolute filesystem path.

        Raises
        ------
        ValueError
            If git returned an empty path.
        """
        path_str = path.as_posix()
        result = await self.run(
            ["rev-parse", "--path-format=absolute", "--git-path", path_str],
            capture_output=True,
            cwd=cwd,
            deadline=deadline,
        )
        text = result.stdout.strip()
        if not text:
            msg = f"empty --git-path output for {path_str!r}"
            raise ValueError(msg)
        resolved = Path(text).expanduser()
        if not resolved.is_absolute():
            base = cwd if cwd is not None else self.root
            resolved = (base / resolved).resolve()
        else:
            resolved = resolved.resolve()
        return resolved

    async def branches(self, *, deadline: Deadline = NO_DEADLINE) -> frozenset[str]:
        """Return repository branch names.

        Parameters
        ----------
        deadline : Deadline, optional
            An optional deadline by which this check must complete before raising a
            `TimeoutError`.  Defaults to an infinite deadline, which causes the command
            to block indefinitely until completion.  If the deadline is earlier than the
            time this method is called, a `TimeoutError` will be raised immediately.

        Returns
        -------
        frozenset[str]
            A set of all (short) branch names in the repository.  Note that this only
            includes branches under `refs/heads/`, and not other refs like tags or
            remotes.

        """
        result = await self.run(
            ["for-each-ref", "--format=%(refname:short)", "refs/heads"],
            capture_output=True,
            deadline=deadline,
        )
        out = {line.strip() for line in result.stdout.splitlines()}
        out.discard("")  # remove empty lines if any
        return frozenset(out)

    @staticmethod
    async def default_branch(*, deadline: Deadline = NO_DEADLINE) -> str:
        """Return the default Git branch name.

        Parameters
        ----------
        deadline : Deadline, optional
            An optional deadline by which this check must complete before raising a
            `TimeoutError`.  Defaults to an infinite deadline, which causes the command
            to block indefinitely until completion.  If the deadline is earlier than the
            time this method is called, a `TimeoutError` will be raised immediately.

        Returns
        -------
        str
            The default branch name configured for this git installation.

        Raises
        ------
        ValueError
            If the default branch could not be determined from git output.
        """
        branch = await run(
            ["git", "var", "GIT_DEFAULT_BRANCH"],
            capture_output=True,
            deadline=deadline,
        )
        result = branch.stdout.strip()
        if not result:
            msg = "default Git branch name could not be determined"
            raise ValueError(msg)
        return result

    async def head_branch(self, *, deadline: Deadline = NO_DEADLINE) -> str | None:
        """Return the current HEAD branch.

        Parameters
        ----------
        deadline : Deadline, optional
            An optional deadline by which this check must complete before raising a
            `TimeoutError`.  Defaults to an infinite deadline, which causes the command
            to block indefinitely until completion.  If the deadline is earlier than the
            time this method is called, a `TimeoutError` will be raised immediately.

        Returns
        -------
        str | None
            The short branch name of the current HEAD, or None if HEAD is detached.

        Raises
        ------
        CommandError
            If Git returns an unexpected symbolic-ref failure.
        ValueError
            If we failed to parse the output or got an empty branch name.
        """
        # attached HEAD: try to read symbolic ref directly
        result = await self.run(
            ["symbolic-ref", "--quiet", "--short", "HEAD"],
            check=False,
            capture_output=True,
            deadline=deadline,
        )
        if result.returncode == 0:
            text = result.stdout.strip()
            if not text:
                msg = "empty symbolic-ref output for HEAD"
                raise ValueError(msg)
            return text
        if result.returncode != 1:
            raise CommandError(
                returncode=result.returncode,
                cmd=result.args,
                output=result.stdout,
                stderr=result.stderr,
            )

        # detached HEAD: let caller decide what to do
        return None

    @staticmethod
    async def supports_relative_paths(*, deadline: Deadline = NO_DEADLINE) -> bool:
        """Return whether this Git supports relative worktree paths.

        Parameters
        ----------
        deadline : Deadline, optional
            An optional deadline by which this check must complete before raising a
            `TimeoutError`.  Defaults to an infinite deadline, which causes the command
            to block indefinitely until completion.  If the deadline is earlier than the
            time this method is called, a `TimeoutError` will be raised immediately.

        Returns
        -------
        bool
            True if both `git worktree add` and `git worktree move` support
            `--relative-paths` according to their help output, false otherwise.
        """
        add_help = await run(
            ["git", "worktree", "add", "-h"],
            check=False,
            capture_output=True,
            deadline=deadline,
        )
        add_text = f"{add_help.stdout}\n{add_help.stderr}".lower()
        if add_help.returncode != 0 or "--relative-paths" not in add_text:
            return False
        move_help = await run(
            ["git", "worktree", "move", "-h"],
            check=False,
            capture_output=True,
            deadline=deadline,
        )
        move_text = f"{move_help.stdout}\n{move_help.stderr}".lower()
        return move_help.returncode == 0 and "--relative-paths" in move_text

    async def bare(self, *, deadline: Deadline = NO_DEADLINE) -> bool:
        """Return whether this repository is bare.

        Parameters
        ----------
        deadline : Deadline, optional
            An optional deadline by which this check must complete before raising a
            `TimeoutError`.  Defaults to an infinite deadline, which causes the command
            to block indefinitely until completion.  If the deadline is earlier than the
            time this method is called, a `TimeoutError` will be raised immediately.

        Returns
        -------
        bool
            True if this repository is a bare repository, false otherwise.

        Raises
        ------
        ValueError
            If we failed to parse the output.
        """
        result = await self.run(
            ["rev-parse", "--is-bare-repository"],
            capture_output=True,
            deadline=deadline,
        )
        value = result.stdout.strip().lower()
        if value == "true":
            return True
        if value == "false":
            return False
        msg = f"invalid --is-bare-repository output: {result.stdout!r}"
        raise ValueError(msg)

    async def worktrees(
        self,
        *,
        deadline: Deadline = NO_DEADLINE,
    ) -> tuple[GitRepository.Worktree, ...]:
        """List all local worktrees for the given Git directory.

        Parameters
        ----------
        deadline : Deadline, optional
            An overall deadline by which the listing must complete before raising a
            `TimeoutError`.  Defaults to an infinite deadline, which causes the command
            to block indefinitely until completion.  If the deadline is earlier than the
            time this method is called, a `TimeoutError` will be raised immediately.

        Returns
        -------
        tuple[GitRepository.Worktree, ...]
            A tuple of worktree entries.  Includes both attached (with branch) and
            detached (without branch) worktrees, which may be filtered by the caller as
            needed.
        """
        out: list[GitRepository.Worktree] = []
        path: Path | None = None
        branch: str | None = None
        result = await self.run(
            ["worktree", "list", "--porcelain"],
            capture_output=True,
            deadline=deadline,
        )
        for raw in result.stdout.splitlines():
            line = raw.strip()
            if not line:
                if path is not None:
                    out.append(self.Worktree(repo=self, path=path, branch=branch))
                path = None
                branch = None
                continue
            if line.startswith("worktree "):
                path = Path(line[len("worktree ") :]).expanduser().resolve()
                continue
            if line.startswith(f"branch {GIT_REF_HEADS_PREFIX}"):
                branch = line[len("branch ") + len(GIT_REF_HEADS_PREFIX) :]
        if path is not None:
            out.append(self.Worktree(repo=self, path=path, branch=branch))
        return tuple(out)

    async def head_worktree(
        self,
        *,
        deadline: Deadline = NO_DEADLINE,
    ) -> GitRepository.Worktree | None:
        """Return the in-repository worktree attached to HEAD.

        Parameters
        ----------
        deadline : Deadline, optional
            An overall deadline by which this check must complete before raising a
            `TimeoutError`.  Defaults to an infinite deadline, which causes the command
            to block indefinitely until completion.  If the deadline is earlier than the
            time this method is called, a `TimeoutError` will be raised immediately.

        Returns
        -------
        GitRepository.Worktree | None
            The worktree registered for the current HEAD branch, or None if HEAD is
            detached, unattached, or attached only to an out-of-repository worktree.
        """
        branch = await self.head_branch(deadline=deadline)
        if branch is None:
            return None
        return await self.get_worktree(branch, deadline=deadline)

    async def get_worktree(
        self,
        branch: str,
        *,
        deadline: Deadline = NO_DEADLINE,
    ) -> GitRepository.Worktree | None:
        """Return the worktree attached to the given branch, if any.

        Parameters
        ----------
        branch : str
            The short branch name to find a worktree for.
        deadline : Deadline, optional
            An overall deadline by which this check must complete before raising a
            `TimeoutError`.  Defaults to an infinite deadline, which causes the command
            to block indefinitely until completion.  If the deadline is earlier than the
            time this method is called, a `TimeoutError` will be raised immediately.

        Returns
        -------
        GitRepository.Worktree | None
            The worktree registered for the given branch, or None if no worktree is
            attached to that branch or if the attached worktree is out-of-repository.

        Raises
        ------
        OSError
            If multiple registered worktrees claim the given branch.
        """
        matches = [
            worktree
            for worktree in await self.worktrees(deadline=deadline)
            if worktree.branch == branch
        ]
        if not matches:
            return None
        if len(matches) > 1:
            paths = ", ".join(str(worktree.path) for worktree in matches)
            msg = f"multiple worktrees are attached to branch {branch!r}: {paths}"
            raise OSError(msg)
        return matches[0]

    async def create_worktree(
        self,
        branch: str,
        target: Path | None = None,
        *,
        create_branch: bool = True,
        quiet: bool = False,
        deadline: Deadline = NO_DEADLINE,
    ) -> GitRepository.Worktree:
        """Create a new worktree for the given branch at the specified target path.

        Parameters
        ----------
        branch : str
            The short branch name to create a worktree for.
        target : Path | None, optional
            The target path to create the worktree at.  Must not already exist.
        create_branch : bool, optional
            If True (the default), then the branch will be created if it does not
            already exist.  If False, then the branch must already exist in the
            repository.
        quiet : bool, optional
            If True, then suppress any non-error output from the git command.  Default
            is False.
        deadline : Deadline, optional
            An overall deadline by which the creation must complete before raising a
            `TimeoutError`.  Defaults to an infinite deadline, which causes the command
            to block indefinitely until completion.  If the deadline is earlier than the
            time this method is called, a `TimeoutError` will be raised immediately.

        Returns
        -------
        GitRepository.Worktree
            A `Worktree` object representing the newly created worktree.

        Raises
        ------
        FileExistsError
            If the target path already exists.
        """
        if target is None:
            target = self.root / branch
        if target.exists():
            msg = "path already exists"
            raise FileExistsError(msg)
        target.parent.mkdir(parents=True, exist_ok=True)
        cmd = ["worktree", "add", "--relative-paths"]
        if create_branch:
            if branch not in await self.branches(deadline=deadline):
                cmd.extend(["-b", branch, str(target)])
            else:
                cmd.extend([str(target), branch])
        else:
            cmd.extend([str(target), branch])
        await self.run(cmd, capture_output=quiet, deadline=deadline)
        return GitRepository.Worktree(repo=self, path=target, branch=branch)

    async def _current_worktree_state(self, *, deadline: Deadline) -> dict[str, Path]:
        current: dict[str, Path] = {}
        for wt in await self.worktrees(deadline=deadline):
            if wt.branch is None:
                continue
            existing = current.setdefault(wt.branch, wt.path)
            if existing != wt.path:
                msg = (
                    f"multiple worktrees mapped to branch '{wt.branch}': {existing} "
                    f"and {wt.path}"
                )
                raise FileExistsError(msg)
        return current

    def _intended_worktree_changes(
        self,
        *,
        updates: Sequence[GitRepository.RefUpdate],
    ) -> tuple[list[str], list[str], list[tuple[str, str]]]:
        # get creation/destruction intent from transaction updates
        created_: dict[str, list[str]] = {}
        destroyed_: dict[str, list[str]] = {}
        created: list[str] = []
        destroyed: list[str] = []
        for update in updates:
            if update.created:
                created.append(update.branch)
                created_.setdefault(update.new, []).append(update.branch)
            elif update.destroyed:
                destroyed.append(update.branch)
                destroyed_.setdefault(update.old, []).append(update.branch)

        # infer rename hints from unambiguous create + destroy pairs on the same object
        renamed: list[tuple[str, str]] = []
        for oid in sorted(set(created_) & set(destroyed_)):
            c = created_[oid]
            d = destroyed_[oid]
            if len(c) == 1 and len(d) == 1:
                old_branch = d[0]
                new_branch = c[0]
                renamed.append((old_branch, new_branch))
                destroyed.remove(old_branch)
                created.remove(new_branch)

        return created, destroyed, renamed

    def _filter_worktree_conflicts(
        self,
        *,
        desired: dict[str, Path],
        current: dict[str, Path],
        created: list[str],
    ) -> dict[str, Path]:
        # sort branches by conflict priority, then filter out any whose slash-separated
        # paths would create a nested worktree conflicts
        winners: list[str] = []
        for branch in sorted(
            desired,
            key=lambda b: (
                0 if b in current else 1,  # prioritize existing
                0
                if b not in created
                else 1,  # ... then prioritize non-created branches
                b,  # ... then break ties lexically
            ),
        ):
            conflict: str | None = None
            for winner in winners:
                if branch == winner:
                    continue
                left_parts = branch.split("/")
                right_parts = winner.split("/")
                min_len = min(len(left_parts), len(right_parts))
                if left_parts[:min_len] == right_parts[:min_len]:
                    conflict = winner
                    break
            if conflict is None:
                winners.append(branch)
                continue
            warn(
                f"skipping branch '{branch}' due nested path conflict with '{conflict}'"
            )

        return {branch: desired[branch] for branch in winners}

    async def _sync_create_worktree(
        self,
        *,
        current: dict[str, Path],
        branch: str,
        target: Path,
        create_branch: bool,
        deadline: Deadline,
    ) -> None:
        try:
            await self.create_worktree(
                branch,
                target=target,
                create_branch=create_branch,
                deadline=deadline,
            )
            current[branch] = target
        except _HOOK_OPERATION_ERRORS as err:
            warn(f"failed to create worktree for branch '{branch}' at {target}:\n{err}")

    async def _sync_move_worktree(
        self,
        *,
        current: dict[str, Path],
        branch: str,
        source: Path,
        target: Path,
        old_branch: str | None = None,
        deadline: Deadline,
    ) -> None:
        try:
            worktree = GitRepository.Worktree(repo=self, path=source, branch=branch)
            await worktree.move(target=target, deadline=deadline)
            if old_branch is not None:
                current.pop(old_branch, None)
            current[branch] = target
        except _HOOK_OPERATION_ERRORS as err:
            warn(
                f"failed to move worktree for branch '{branch}' from {source} "
                f"to {target}:\n{err}"
            )

    async def _sync_destroy_worktree(
        self,
        *,
        current: dict[str, Path],
        branch: str,
        path: Path,
        deadline: Deadline,
    ) -> None:
        try:
            worktree = GitRepository.Worktree(repo=self, path=path, branch=branch)
            if await worktree.destroy(deadline=deadline):
                current.pop(branch, None)
        except _HOOK_OPERATION_ERRORS as err:
            warn(f"failed to destroy worktree for branch '{branch}' at {path}:\n{err}")

    async def sync_worktrees(
        self,
        updates: Sequence[GitRepository.RefUpdate] = (),
        *,
        deadline: Deadline = NO_DEADLINE,
    ) -> None:
        """Converge worktrees to the authoritative branch set.

        Parameters
        ----------
        updates : Sequence[GitRepository.RefUpdate], optional
            The parsed reference updates received from git on stdin, which will be used
            to derive explicit intent for branch creations and destructions, as well as
            implicit hints for branch renames where creation and destruction are paired
            on the same object.  If omitted, then convergence will transform directly
            from the current state to the desired state without any intent-based
            guidance.
        deadline : Deadline, optional
            An overall deadline by which the convergence must complete before raising a
            `TimeoutError`.  Defaults to an infinite deadline, which causes the command
            to block indefinitely until completion.  If the deadline is earlier than the
            time this method is called, a `TimeoutError` will be raised immediately.
        """
        # non-bare repositories are treated as single-worktree mode
        if not await self.bare():
            return

        # derive current and desired branch-to-path mappings
        current = await self._current_worktree_state(deadline=deadline)
        desired = {branch: (self.root / branch) for branch in await self.branches()}

        # derive explicit intent from transaction updates, preserving order
        created, destroyed, renamed = self._intended_worktree_changes(updates=updates)
        desired = self._filter_worktree_conflicts(
            desired=desired,
            current=current,
            created=created,
        )

        # apply rename hints first (when they map cleanly to current state)
        for old_branch, new_branch in renamed:
            source = current.get(old_branch)
            if source is None:
                continue
            target = desired.get(new_branch)
            if target is None or new_branch in current:
                continue
            await self._sync_move_worktree(
                current=current,
                branch=new_branch,
                source=source,
                target=target,
                old_branch=old_branch,
                deadline=deadline,
            )

        # apply explicit destroys for branches still present in current state
        for branch in destroyed:
            path = current.get(branch)
            if path is None or branch in desired:
                continue
            await self._sync_destroy_worktree(
                current=current,
                branch=branch,
                path=path,
                deadline=deadline,
            )

        # apply explicit creates for branches that are still missing
        for branch in created:
            if branch in current or branch not in desired:
                continue
            target = desired[branch]
            await self._sync_create_worktree(
                current=current,
                branch=branch,
                target=target,
                create_branch=True,
                deadline=deadline,
            )

        # remove branches no longer present in the repository
        stale = set(current) - set(desired)
        for branch in sorted(stale):
            path = current[branch]
            await self._sync_destroy_worktree(
                current=current, branch=branch, path=path, deadline=deadline
            )

        # move branches that are present but located at non-canonical paths
        shared = set(current) & set(desired)
        for branch in sorted(shared):
            source = current[branch]
            target = desired[branch]
            if source == target:
                continue
            await self._sync_move_worktree(
                current=current,
                branch=branch,
                source=source,
                target=target,
                deadline=deadline,
            )

        # create worktrees for branches that don't yet have one
        missing = set(desired) - set(current)
        for branch in sorted(missing):
            target = desired[branch]
            await self._sync_create_worktree(
                current=current,
                branch=branch,
                target=target,
                create_branch=False,
                deadline=deadline,
            )
